INSERT INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order, is_delete) VALUES (1, '呂布', 'リョフ', 5, 7, 100, 59, 80, 38, 3.37, 0.33, 2.24, 0.24, '三国時代', '後漢末の武将。董卓に仕えたのち自立するが、曹操に敗れ処刑された。武勇で名高い。', 1, 0) ON CONFLICT(id) DO UPDATE SET name = excluded.name, reading = excluded.reading, rarity = excluded.rarity, cost = excluded.cost, atk = excluded.atk, int = excluded.int, guts = excluded.guts, pol = excluded.pol, atk_growth = excluded.atk_growth, int_growth = excluded.int_growth, guts_growth = excluded.guts_growth, pol_growth = excluded.pol_growth, era = excluded.era, biography = excluded.biography, sort_order = excluded.sort_order, is_delete = excluded.is_delete;
