INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (1, '天下無双', NULL, NULL, 'パッシブ', '距離2以下の目標に与える全ダメージ18%（45%)増加、距離2以上の攻撃から受ける全ダメージ11%（20%）減少する。同時に3部隊以上から攻撃を受ける時、ダメージ増加効果は無効となる', 1, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (2, '百歩戟中', NULL, '弓のみ', 'パッシブ', '部隊の与える全ダメージが11%（20%）（武力加算）上昇し、移動中の目標へ命中率12%（30%）上昇。自部隊より高い位置にいる目標への命中率は21%（30%）上昇する。', 2, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (3, '危機怯まず', NULL, NULL, 'パッシブ', '部隊の全被ダメ減少 5.5%（10%）減少。直前2秒間に攻撃を受けた敵部隊から受けた攻撃数に応じてさらに2%増加（最大11.5%【25％】まで上昇）', 3, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (4, '孤城固守', NULL, NULL, 'パッシブ', '部隊の全被ダメ6%【15％】（胆力補正）減少。【隣接】に存在する敵1部隊につき、ダメージ軽減効果が追加増加 3.5%【8%】', 4, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (5, '槍は龍の如く', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に1~3回の武功ダメージ 75%【165%】を与える。槍兵系兵種の場合、2～3回となる。', 5, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (6, '単騎駆け', NULL, NULL, 'パッシブ', '【隣接】に存在する敵部隊1部隊につき、部隊の全与ダメ5.5%【10%】上昇（武力補正）、最大で15%【60%】まで上昇', 6, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (7, '怒髪衝天', NULL, NULL, '連鎖', '通常攻撃後、26％【35％】の確率で敵部隊に武功ダメージ 。115%【250％】、敵の怒気を3.5【8】減少。自身は○○状態の影響を受けなくなる。効果は2秒間持続', 7, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (8, '岳家槍陣', NULL, '槍のみ', 'パッシブ', '騎兵からの全被ダメ6.5%【20％】減少（胆力補正）、騎兵に与える全与ダメ6.5%【20％】増加（武力補正）', 8, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (9, '東征西討', NULL, NULL, '怒気技', '主将時、怒気100以上で全怒気を消費し、【前方扇形範囲】内最大4部隊に武攻ダメージ 550%【1000% 怒気補正】、敵1部隊毎にダメージ率-60%', 9, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (10, '千里転戦', NULL, '弓以外', 'パッシブ', '戦闘状態にない時、移動速度+55【100】。【隣接】に存在する味方または友軍部隊1部隊につき、部隊の全与ダメを5.5%【10%】（武力補正）上昇させる。最大で45%まで', 10, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (11, '矢神', '弓のみ', NULL, 'パッシブ', '自身の通常攻撃クリティカル率を5.5%【10%】上昇。通常攻撃の対象の【隣接】の1部隊の敵部隊に追加で通常攻撃ダメージ 35%【80％】を与える。追加ダメージは連鎖を発動しない。', 11, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (12, '射日', NULL, '弓のみ', 'パッシブ', '部隊のアクティブスキルおよび怒気技のクリティカル率が6.5%【20%】上昇。対象部隊の高度が自身より高い場合、さらにアクティブスキルと怒気技のクリティカル率が18.5%【50％】増加（武力補正）', 12, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (13, '克敵の勝', NULL, NULL, 'パッシブ', '部隊の有利兵種効果が10.5%【15%】増加する（知力補正）', 13, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (14, '兵は常形無し', NULL, NULL, 'パッシブ', '部隊がダメージを受ける際、不利兵種による被ダメ増加の影響を受けず、与ダメ時の有利兵種効果が12%【30%】増加する。（知力補正）', 14, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (15, '八九玄功', NULL, NULL, 'パッシブ', '自身のダメージを与える時、30%【75%】の確率で敵の被ダメ減少効果を無視し、さらに自分は10レベルごとに追加で10ポイントの能力を獲得する。自身が40レベルの際、第2スキルレベルが+1、45レベルの際は第3スキルレベルが+1、50レベルの際は第2、第3レベルがさらに+1される。', 15, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (16, '九転の元功', NULL, NULL, 'パッシブ', '部隊は全てのデバフ状態を無効化し、ダメージを受ける度、そのダメージ元の部隊に対して全被ダメを2%減少（胆力補正）。ダメージ元1部隊あたり2秒ごとに1回まで最大で12%【30%】減少。戦闘離脱まで持続', 16, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (17, '連営の火', NULL, NULL, '能動', '25%の確率で発動し、敵軍部隊に知攻ダメージ 120%【300%】を与え、かつマスを【燃焼】状態（ダメージ90%【180%】）にする。持続時間4秒間。2秒後、燃焼は燃焼していない敵軍がいるマスに優先して蔓延する。持続時間4秒間。最大2回まで拡大可能。対象マスがすでに燃焼状態なら、知攻ダメージ 120%【300%】を与え、さらに500の固定兵力ダメージ（兵科影響あり）を追加で与える。', 17, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (18, '絶命の生還', NULL, NULL, 'パッシブ', '部隊が兵力上限x32%【50%】以下の時、2秒ごとに部隊の兵力が一定量回復する（回復率 70%【250%】知力補正）。非戦闘時でも回復可能。出征前の兵力が10000を超える場合、致命ダメージを受けた時に【ダメージ無効】と【免疫】状態に入り、12秒持続し、100秒以内に再発動できない。', 18, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (19, '阻撃戦', '弓以外', NULL, 'パッシブ', '【円形範囲】内の敵部隊が攻撃後、自身未移動時37%【100%】確率で攻撃元に武攻ダメージ 55%【100%】、前2秒に受けた攻撃1部隊毎に12%【30%】追加。最大60%【150%】2秒毎に1部隊最大1回発動。反撃スキル', 19, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (20, '生生流転', NULL, NULL, 'パッシブ', '部隊が300兵力回復するごとに、部隊の与ダメージが1%【10%】増加（武力補正）。最大で55%【100%】。同時に部隊の被ダメを1%【10%】減少。2秒間持続。効果は重ねがけ可能。', 20, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (21, '名乗り', NULL, NULL, '能動', '11.5%【25%】の確率で発動し、自身の【円形範囲】内の2部隊の敵部隊を【挑発】状態にし、部隊に【通常攻撃被ダメージ軽減】状態を付与し、受ける通常攻撃ダメージを23％【50%】軽減し、4秒間持続', 21, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (22, '一夫当関', NULL, NULL, 'パッシブ', '部隊が攻撃対象となった際、敵部隊の連鎖スキル発動率が6％【15%】減少します。（胆力補正）', 22, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (23, '忠君衛道', NULL, NULL, 'パッシブ', '【隣接】の味方部隊被ダメージ時、部隊が22%【40%】のダメージを肩代わりする。（ダメージの22%【40%】軽減。胆力補正）。他効果発動不可', 23, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (24, '堅城守備', NULL, NULL, 'パッシブ', '部隊が弓兵から受ける全ダメージが32%【50%】減少（胆力補正）し、弓兵以外から受ける全ダメージ6.5%【20%】減少する。（胆力補正）', 24, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (25, '歯には歯を', NULL, NULL, 'パッシブ', '２秒ごとに敵部隊へ武攻ダメージ 30%を与え、さらに目標部隊が直前2秒間に行った通常攻撃の回数ごとにダメージ率が加算され、1回ごとに追加13%【40%】ダメージ率が上昇します。', 25, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (26, '目には目を', NULL, NULL, 'パッシブ', '直近10秒以内に目標部隊からのダメージを受けている場合、その部隊に対して与える全ダメージが12%【30%】増加します。（武力補正）', 26, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (27, '完計', NULL, NULL, '能動', '26%【35%】の確率で発動し、まず目標部隊が自身から得ている【中毒】状態を処理し、その後、敵部隊を【中毒】状態（ダメージ率87%【150%】）にし、6秒間持続', 27, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (28, '算無遺策', NULL, NULL, 'パッシブ', '部隊の全ての武将はアクティブスキルを発動するたびに、その発動した武将の武力と知力が13【40】（知力補正）上昇し、2秒間持続する', 28, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (29, '猛志常在', NULL, NULL, 'パッシブ', '部隊の怒気下限が23【50】まで上昇し、怒気の自然回復速度は2秒ごとに5に減少する', 29, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (30, '奮死', NULL, NULL, 'パッシブ', '部隊が直前10秒以内に失った兵力が13000を超える場合、部隊の全ダメージのクリティカル率が55%【100%】上昇し、クリティカルダメージが55%【100%】（武力補正）増加する。', 30, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (31, '不動は山の如く', NULL, NULL, 'パッシブ', '戦闘開始後、2秒ごとに1層の【属性上昇】状態を獲得し、自身の武力・知力・胆力が5増加する。この効果は最大3【12】層まで重複可能。層数が3層を超えると挑発状態を無効化する。移動するたびに層数はリセットされる。', 31, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (32, '晩節隆盛', NULL, NULL, 'パッシブ', '部隊の負傷率が19%【10%】減少し、【治療禁止】状態となる。受ける全ダメージが11%【20%】減少し、与える全ダメージが11%【20%】（武力補正）上昇する。', 32, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (33, '玄甲鉄騎', NULL, NULL, 'パッシブ', '部隊が受ける武攻ダメージが7%【25%】減少し、知攻ダメージ（被ダメ）が19%【10%】増加する。また、距離が1を超える全ダメージについては、さらに15%減少する。', 33, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (34, '百戦の奇略', NULL, NULL, 'パッシブ', '部隊の残兵力が60%以上の場合、与える全ダメージが12%【30%】（武力補正）上昇し、それ未満の場合は受ける全ダメージが11%【20%】減少する。', 34, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (35, '屠所の刃', NULL, NULL, 'パッシブ', '部隊の全武将がダメージを与える時、敵部隊の胆力6%【15%】を無視する。', 35, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (36, '破竹の勢い', NULL, NULL, 'パッシブ', '部隊の連鎖スキル発動率が5%上昇し、連鎖スキルダメージが6.5%【20%】（武力補正）増加する。', 36, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (37, '鉄槍破敵', NULL, NULL, '連鎖', '通常攻撃後、30%の確率で敵部隊に武攻ダメージ 95%【230％】を与え、敵の全武将を〇〇状態にし、胆力を6【15】減少させる。効果4秒間持続', 37, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (38, '鉄胆の槍塊', NULL, NULL, 'パッシブ', '部隊所属の全武将は、各行動ごとに30%【75％】の確率（武力補正）で【連撃】状態を2秒間獲得します。刀兵系・騎兵系兵種の場合、連撃発動率が15%減少し、弓兵系兵種の場合は連撃発動率が40%減少します。各武将ごとに個別判定されます。', 38, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (39, '怒破万軍', NULL, NULL, '怒気技', '主将時に怒気110以上の時、全怒気を消費し、【円形範囲】内の最大6部隊に武攻ダメージ 315%【540%】（怒気補正）を与え、3部隊以上の部隊にダメージを与えた場合、怒気回復効率を50%上昇させ、次にこのスキルを発動するまで持続する。', 39, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (40, '短兵近接', NULL, '弓以外', 'パッシブ', '【隣接】の敵部隊に与えるアクティブ及び連鎖ダメージを12.5%【35%】（武力補正）上昇させる', 40, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (41, '烈火衝天', NULL, NULL, '怒気技', '主将時に怒気100以上の時、全怒気を消費し、自身前方【直線範囲】内の敵部隊に智攻ダメージ 325%【550%】（怒気補正）、対象が燃焼タイル上にいる場合、ダメージ率は670%【1300%】。タイルを【燃焼】状態（ダメージ率90%【180%】）にし、8秒間持続', 41, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (42, '焼き尽くし', NULL, '兵器含む', 'パッシブ', '部隊が器械および建築物に与える全ダメージが65%【200％】増加します。（知力補正）', 42, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (43, '万矢斉射', '弓のみ', NULL, '能動', '31%【40%】の確率で発動し、対象部隊及びその【隣接】の敵部隊に武功ダメージ 86%【140%】を与え、敵部隊が1部隊多いごとにダメージ率が20%減少し、最大80%まで減少する。', 43, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (44, '弱点攻破', NULL, NULL, 'パッシブ', '敵部隊に異なるデバフ状態が1種類あるごとに、その部隊への全ダメージが3.7%【10%】増加（武力補正）。最大で50%まで', 44, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (45, '刮骨療傷', NULL, NULL, '能動', '21%【30%】の確率で発動し、部隊の兵力を一定回復 220%【400%】（知力補正）、さらに自身部隊が【免疫】状態を4秒間獲得', 45, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (46, '神医', NULL, NULL, 'パッシブ', '部隊の負傷率+1%【10%】、回復効果が35%【80%】増加する（知力補正）', 46, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (47, '策術深遠', NULL, NULL, '連鎖', '通行攻撃後、32%【50%】の確率で敵部隊に知攻ダメージ 66%【120%】を与え、対象部隊の全ての強化状態を解除する。', 47, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (48, '母儀天下', NULL, NULL, 'パッシブ', '部隊が与える全ダメージが6%【15%】増加します。（知力補正）。さらに5怒気ごとに追加で1%増加します。', 48, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (49, '猿臂の強弓', '弓のみ', NULL, 'パッシブ', '自身の通常攻撃に貫通効果が付与され、攻撃範囲内で同一直線かつ同じ高さにいる最大4つの敵部隊に通常攻撃ダメージを与える。ダメージ率 80%/57%【120%】/90%【180%】/115%【250%】の順となる。連鎖は最初にダメージを受けた部隊のみ発動する。', 49, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (50, '飛将軍', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが13%【40%】（胆力補正）減少します。部隊が何らかのダメージを与えた後は、被ダメージ減少効果が消失し、代わりに全ダメージが11%【20%】（武力補正）増加します。この効果は戦闘終了まで持続します。', 50, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (51, '破軍奪旗', '全', NULL, '能動', '31%【40%】の確率で発動し、敵部隊に武攻ダメージ 95%【230%】を与える。直前2秒間の兵力損失が2000を超える場合、ダメージ率は225%【450%】となる。', 51, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (52, '十騎落城', NULL, NULL, 'パッシブ', '部隊の兵力が目標部隊の43.5%【30%】以上の時、その部隊に与える全ダメージが出生時の初期兵力を基準として計算される。', 52, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (53, '太祖長拳', NULL, NULL, '能動', '31%【40%】の確率で発動し、敵部隊に武功ダメージ 110%【200%】を与える。前回と同じ攻撃対象なら、このスキルのダメージ率が6%【15%】増加（最大15回まで重複）。攻撃対象が異なる場合、ダメージ率増加効果はリセットされる。', 53, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (54, '杯酒解兵', NULL, '弓以外', 'パッシブ', '部隊がアクティブスキルで直接ダメージを与えた時、追加で65【200】兵力（武力補正）分の固定ダメージを与える。間接ダメージ効果時は追加ダメージ18.5【50】兵力の固定ダメージとなる。', 54, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (56, '致命の突撃', NULL, '馬のみ', 'パッシブ', '部隊が突撃状態（移動速度が兵種基礎速度以上かつ10秒間維持）で初めて攻撃する時、部隊兵力x1.1%【2%】分の固定ダメージを追加で与える。', 56, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (57, '奇正', NULL, NULL, 'パッシブ', '部隊全武将がアクティブスキルまたは連鎖スキルを発動するたびに、自身の与ダメージが5.5%【10%】上昇し、ダメージを与える際に敵の胆力6%【15%】を無視する。2秒間持続し、効果は重複可能。', 57, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (58, '鴛鴦陣', NULL, NULL, 'パッシブ', '【円形範囲】内の味方槍兵部隊が与えるダメージを6%【15%】（武力補正）上昇させ、味方刀兵部隊が受ける回復効果を12%【30%】上昇させ、味方弓兵部隊のクリティカル率を+5.5%【10%】する。', 58, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (59, '援攻', NULL, NULL, 'パッシブ', '行軍時、最初の2秒間に自身の【隣接】に存在し対象にダメージを与えた味方または友軍部隊が1部隊存在するごとに、自身が13%【40%】の確率で追加で1回の通常攻撃を行い、各部隊ごとに独立判定され、最大で3回の追加通常攻撃が可能。', 59, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (60, '軍師', NULL, NULL, 'パッシブ', '怒気スキル発動後、部隊が受ける全ダメージが22%【40％】減少（胆力補正）、減少効果は2秒ごとに4%ずつ減少する。', 60, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (61, '銅筋鉄骨', NULL, NULL, 'パッシブ', '部隊は2秒ごとに最大7700【5000】の兵力しか失わない。固定ダメージは無効化できない。部隊のクリティカル率が90%減少する。', 61, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (62, '百挫不屈', NULL, NULL, 'パッシブ', '部隊が前6秒以内にデバフ状態になるごとに、与える全ダメージが5.5%【10%】増加、最大で23%【50%】まで（武力補正）', 62, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (63, '乾坤策定', NULL, NULL, 'パッシブ', '部隊は【挑発】・【鈍足】状態を無効化する。2秒以内に3未満の部隊から攻撃を受けた場合、主将が与える全ダメージが知力補正で6%【15%】上昇。3以上の部隊から攻撃を受けた場合、部隊が受ける全ダメージが11％【20%】減少。5以上の部隊から攻撃を受けた場合、全ての増減ダメージ効果が無効化される。', 63, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (64, '杙道明修', NULL, NULL, 'パッシブ', '部隊が移動中は【挑発】・【鈍足】状態を無効化。さらに戦闘に突入し初回ダメージ発生後、部隊の与える全ダメージが12%【30%】増加（知力補正）。増加効果は4秒ごとに1%減少', 64, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (65, '飛火矢', '弓のみ', NULL, 'パッシブ', '通常攻撃時、10%の確率で対象を【灼傷】状態（ダメージ率120%【300%】）にし、4秒間持続。対象が林地にいる場合、燃灼発生確率が30%まで上昇し、通常攻撃で対象タイルが【燃焼】状態（ダメージ率70%【160%】4秒間持続）となる。対象が燃焼または燃灼状態の場合、通常攻撃で50%の確率で【鈍足】状態となり、移動速度が22%【40%】低下する。4秒間持続', 65, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (66, '高所の利', NULL, '弓のみ', 'パッシブ', '自身部隊が与える全ダメージが16%【25%】増加します。部隊の高度が目標部隊より高い場合、与える全ダメージが27%【45%】まで増加します。（武力補正）', 66, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (67, '合奏', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 65%【】を与え、部隊に【武攻ダメージ増加】状態を付与する。武攻5%（知力補正）上昇し、1部隊につき最大5回まで重ね掛け可能', 67, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (68, '剣舞', NULL, NULL, 'パッシブ', '部隊が攻撃する際、直前2秒間と同じ目標を攻撃している場合、部隊の与える全ダメージが2%上昇し、最大7【25】回まで重複可能。攻撃目標が異なる場合、このダメージ上昇効果はリセットされる。', 68, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (69, '輔周討紂', NULL, NULL, 'パッシブ', '主将が怒気技を発動した際、同時に敵部隊1体に知攻ダメージ 380%【1100%】を与え、自身の怒気を11【20】回復します。', 69, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (70, '休養生息', NULL, NULL, 'パッシブ', '2秒ごとに部隊の兵力が一定量回復する（回復率 65%【200%】知力補正）。非戦闘時にも回復する。', 70, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (71, '百発百中', '弓のみ', NULL, 'パッシブ', '部隊の射程が1減少し、距離2以下の目標に与える全ダメージが15%【60%】増加、命中率55%【100％】上昇します。', 71, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (72, '百歩穿楊', NULL, '弓のみ', 'パッシブ', '自身部隊の射程が1増加し、距離が3以上の敵部隊に対して全ダメージが1%【10%】増加します。（武力補正）', 72, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (73, '閉月', NULL, NULL, 'パッシブ', '自身が【通常攻撃不可】状態に陥る代償として、部隊アクティブスキル発動率が5.5%【10%】増加します。', 73, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (74, '驚鴻の舞', NULL, NULL, 'パッシブ', '部隊のアクティブスキル発動率が4%【13%】増加します。（知力補正）', 74, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (75, '弦鳴甲破', NULL, NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 60%【150%】を与え、【被ダメージ増加】状態にする。この状態中、受ける全ダメージが1%【10%】上昇し、2秒間持続', 75, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (76, '戦場の激戦', NULL, NULL, 'パッシブ', '部隊が与える全てのダメージが3.4%【7】（武力補正）上昇させる。
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (77, '攻伐九策', NULL, NULL, '能動', '25%の確率で発動し、敵部隊に知攻ダメージ 245%【650%】を与える。9回目以降はこのスキルの基本発動率が戦闘離脱まで半分になる。', 77, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (78, '百工の祖', NULL, NULL, 'パッシブ', '同盟器械操作中、2秒ごとに耐久を5【50】回復（知力補正）、戦闘中は回復効果が3倍になる。', 78, 0);
