INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (85, '威震辺境', NULL, NULL, 'パッシブ', '自身の通常攻撃ダメージ21%【30%】増加し、自身の連鎖ダメージが21%【30%】増加する。これらのダメージ増加効果は2秒ごとに0.5%ずつ減少し、最大10%まで減少する。戦闘状態を離脱するまで持続する。', 85, 0);
