INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (139, '博識多才', NULL, NULL, 'パッシブ', '生産系の内政官を担当すると、該当する基礎資源算出が650【2000】増加する。', 139, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (140, '銅製部品', NULL, '兵器のみ', 'パッシブ', '衝車・投石時、部隊の全武将の武力+22【+40】、胆力+22【+40】', 140, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (141, '敵鋒挫き', NULL, NULL, 'パッシブ', '部隊が受けるアクティブスキルダメージが6%【15%】減少する。', 141, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (142, '堅守の意志', NULL, NULL, 'パッシブ', '部隊の士気減少速度が30%減少し、受けるアクティブスキルのダメージが7%【25%】減少', 142, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (143, '八方馬踏', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 75%【210%】を与える。対象兵種を克服している場合、対象部隊を【治療禁止】状態にし、4秒間持続。', 143, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (144, '遠射', NULL, '弓のみ', 'パッシブ', '自身の部隊は距離3以上の敵部隊に与える全ダメージが4%【13%】増加する。スキルLv10で自身部隊の射程が1増加し、かつ距離3以上の目標を攻撃時、命中率-15%', 144, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (145, '弦鳴雁落', '弓のみ', NULL, '能動', '21%【30%】の確率で発動し、敵部隊に武攻ダメージ 90%【225%】を与える。敵部隊の高度が自身より高い場合、ダメージ率がさらに25%【70%】増加', 145, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (146, '雁射る', NULL, '弓のみ', 'パッシブ', '対象部隊の高さが自身より高い場合、主将のクリティカル率+13%【40%】（武力補正）', 146, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (147, '力借り', NULL, NULL, '能動', '20%【65%】の確率で発動し、部隊内の他の武将を【通常攻撃不可】状態にし、2秒間持続。自身は通常攻撃をもう1回追加で行える。', 147, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (148, '鶏鳴に舞う', NULL, NULL, 'パッシブ', '2秒ごとに部隊のデバフ状態を1つ解除する。戦闘開始後、部隊の全武将は100秒間アクティブスキル発動率が4.5%【9%】増加し、その後は発動率増加効果が失われ、戦闘終了まで継続する。', 148, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (149, '商聖', NULL, NULL, 'パッシブ', '交易官を担当する場合、市場取引の比率が2.5%【7%】増加する。', 149, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (150, '急流勇退', NULL, NULL, 'パッシブ', '戦闘開始後、部隊が与える全ダメージが8.5%【22%】増加（知力補正）、さらに増加しダメージ効果は10秒ごとに1%減少', 150, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (151, '速戦即決', NULL, NULL, '能動', '21%【30%】の確率で発動し、敵部隊に知攻ダメージ 85%【220%】を与える。また、戦闘開始前100秒間、ダメージ率が155%【290%】に上昇。', 151, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (152, '分流合撃', NULL, NULL, 'パッシブ', '主将は行動のたびに42%【60%】の確率で【連撃】状態を2秒間獲得し、さらに連撃を得た場合、副将が与える全ダメージが6.5%【20%】増加。2秒間持続。', 152, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (153, '論戦', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に知攻ダメージ 125%【260%】を与える。15回目以降、このスキルのダメージ率は100%減少し、退場まで持続。', 153, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (154, '一気呵成', NULL, NULL, 'パッシブ', '戦闘開始後、最初の100秒間、部隊が与える全ダメージが11%【20%】増加する（知力補正）、100秒以降は全ダメージが5.5%【10%】増加し、戦闘終了まで持続する（知力補正）', 154, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (155, '金剛', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが2.4%【6%】減少', 155, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (156, '悪鎮め', NULL, NULL, 'パッシブ', '部隊の連鎖スキル発動確率 +3.5%【+8％】', 156, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (157, '大放談', NULL, NULL, '能動', '30%の確率で発動し、敵軍部隊に知攻ダメージ 65%【200%】を与える。', 157, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (158, '窮地生還', NULL, NULL, 'パッシブ', '部隊兵力が31%【40%】未満の時、移動速度+37【+100】、回復効果が46%【100%】増加する', 158, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (159, '暗殺', NULL, NULL, '能動', '30%の確率で発動し、武攻ダメージ 45%【180】を与え、このダメージは20%の確率でクリティカルになる。', 159, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (160, '図窮の寸鉄', NULL, NULL, 'パッシブ', '戦闘開始後、部隊が与える全ダメージが5%増加し、増加効果は4秒ごとに0.5%ずつ上昇し、最大で6%【15%】（武力補正）まで上昇する。', 160, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (161, '怒斬り', NULL, NULL, '怒気技', '主将担当時、怒気が100以上の際、全怒気を消費し、敵部隊に武攻ダメージ 600%【1050%】（怒気補正）を与える。', 161, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (162, '威名', NULL, NULL, 'パッシブ', '部隊が与える全ダメージが1%【5.5%】上昇、自身の武力が敵軍師より高い場合は効果が2%【11%】上昇', 162, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (163, '旗揚げ', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に武攻ダメージ 60%【195％】を与える。', 163, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (164, '鴻鵠の志', NULL, NULL, 'パッシブ', '部隊が与える通常攻撃ダメージが17%【35%】増加し、兵力が敵部隊より少ない場合は34%【70%】増加となる。', 164, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (165, '機略授く', NULL, NULL, '能動', '35%の確率で発動し、主将が与える全ダメージが13%【40%】上昇、2秒間持続', 165, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (166, '紅箋点兵', NULL, NULL, 'パッシブ', '戦闘開始後、部隊全武将の武力・知力・胆力+6【+15】', 166, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (167, '治療', NULL, NULL, '能動', '30%の確率で発動し、部隊の兵力を一定量回復 110%【200%】知力補正', 167, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (168, '林下の風雅', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが1%【5.5%】減少し、自身の知力が敵部隊軍師より高い場合は2%【11%】減少となる。', 168, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (169, '直突本陣', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に武攻ダメージ 120%【300%】を与え、【隣接】の敵部隊数＞1かつ隣接に味方または友軍部隊がいない場合、ダメージ率は225%【450%】となる。', 169, 0);
INSERT INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order, is_delete) VALUES (170, '琴瑟の調べ', NULL, NULL, 'パッシブ', '主将が怒気スキルを発動すると、部隊がダメージ量x 53%【125%】分の兵力を回復する。', 170, 0);
